    { "chapter": 1, "id": "1-8", "q": "To create radiation there must be a ______.", "opts": ["(A) direct charge", "(B) time-varying charge", "(C) decelerating charge"], "ans": "C" },
    { "chapter": 1, "id": "1-9", "q": "Radiation can be created by ______.", "opts": ["(A) smooth wires", "(B) discontinuous wires", "(C) infinite-length wires"], "ans": "B" },
    { "chapter": 1, "id": "1-10", "q": "Radiation can be created by ______.", "opts": ["(A) smooth wires", "(B) bent wires", "(C) infinite-length wires"], "ans": "B" },
    { "chapter": 1, "id": "1-11", "q": "The distance between two successive half-period free-space waves (bunches) is ______.", "opts": ["(A) λ/4", "(B) λ/2", "(C) λ"], "ans": "B" },
    { "chapter": 1, "id": "1-12", "q": "The length L (0 < L < λ) of a center-fed wire/dipole whose current maximum occurs at the feed equals ______.", "opts": ["(A) 0.25 λ", "(B) 0.5 λ", "(C) 1.0 λ"], "ans": "B" },

    { "chapter": 2, "id": "2-1", "q": "A radiator having equal radiation in all directions is a:", "opts": ["(A) directional radiator", "(B) isotropic radiator", "(C) guided radiator"], "ans": "B" },
    { "chapter": 2, "id": "2-2", "q": "A pattern that is essentially nondirectional in a given plane and directional in any orthogonal plane is:", "opts": ["(A) directional", "(B) omnidirectional", "(C) isotropic"], "ans": "B" },
    { "chapter": 2, "id": "2-3", "q": "A radiator that radiates/receives more effectively in some directions than others is a:", "opts": ["(A) directional antenna", "(B) omnidirectional antenna", "(C) isotropic antenna"], "ans": "A" },
    { "chapter": 2, "id": "2-4", "q": "The plane containing the electric-field vector and the direction of maximum radiation is the:", "opts": ["(A) E-plane", "(B) H-plane", "(C) D-plane"], "ans": "A" },
    { "chapter": 2, "id": "2-5", "q": "The plane containing the magnetic-field vector and the direction of maximum radiation is the:", "opts": ["(A) E-plane", "(B) H-plane", "(C) D-plane"], "ans": "B" },
    { "chapter": 2, "id": "2-6", "q": "A portion of the radiation pattern bounded by regions of relatively weak radiation is a radiation ______.", "opts": ["(A) efficiency", "(B) lobe", "(C) impedance"], "ans": "B" },
    { "chapter": 2, "id": "2-7", "q": "The radiation lobe containing the direction of maximum radiation is the:", "opts": ["(A) minor", "(B) major", "(C) lobe"], "ans": "B" },
    { "chapter": 2, "id": "2-8", "q": "The region most immediate to the antenna, where the reactive field predominates, is the:", "opts": ["(A) far-field region", "(B) radiating near-field region", "(C) reactive near-field region"], "ans": "C" },
    { "chapter": 2, "id": "2-9", "q": "The region where the angular field distribution is essentially independent of distance and the real power density predominates is the:", "opts": ["(A) far-field region", "(B) radiating near-field region", "(C) reactive near-field region"], "ans": "A" },
    { "chapter": 2, "id": "2-10", "q": "The region between the reactive near-field and the far-field is the:", "opts": ["(A) radiating near-field region", "(B) Fraunhofer region", "(C) Friis region"], "ans": "A" },
    { "chapter": 2, "id": "2-11", "q": "In MKS units, power density has units of:", "opts": ["(A) watts/meter", "(B) watts/meter squared", "(C) watts/unit solid angle"], "ans": "B" },
    { "chapter": 2, "id": "2-12", "q": "Radiation intensity is related to radiation (power) density by:", "opts": ["(A) r", "(B) r squared", "(C) 1/r squared"], "ans": "B" },
    { "chapter": 2, "id": "2-13", "q": "The ratio of the radiation intensity of an antenna to the radiation intensity of an isotropic source is the:", "opts": ["(A) gain", "(B) directivity", "(C) efficiency"], "ans": "B" },
    { "chapter": 2, "id": "2-14", "q": "The ratio 4π over the beam solid angle is the:", "opts": ["(A) gain", "(B) directivity", "(C) efficiency"], "ans": "B" },
    { "chapter": 2, "id": "2-15", "q": "The ratio of the gain to the directivity of an antenna is the:", "opts": ["(A) aperture efficiency", "(B) reflection efficiency", "(C) radiation efficiency"], "ans": "C" },
    { "chapter": 2, "id": "2-16", "q": "The directivities D_theta and D_phi are the:", "opts": ["(A) θ directivities", "(B) φ directivities", "(C) partial directivities"], "ans": "C" },
    { "chapter": 2, "id": "2-17", "q": "In D0 = 4π/Ω_A, the quantity Ω_A is the:", "opts": ["(A) beam efficiency", "(B) beam bandwidth", "(C) beam solid angle"], "ans": "C" },
    { "chapter": 2, "id": "2-18", "q": "The angular separation between two identical points on an amplitude pattern is the:", "opts": ["(A) bandwidth", "(B) beamwidth", "(C) lobe"], "ans": "B" },
    { "chapter": 2, "id": "2-19", "q": "The range of frequencies over which an antenna's performance meets a standard is the:", "opts": ["(A) bandwidth", "(B) beamwidth", "(C) lobe"], "ans": "A" },
    { "chapter": 2, "id": "2-20", "q": "The figure traced in time by the tip of the time-varying E-field vector at a fixed point, in a plane normal to propagation, defines the:", "opts": ["(A) gain", "(B) directivity", "(C) polarization"], "ans": "C" },
    { "chapter": 2, "id": "2-21", "q": "Two orthogonal field components of equal amplitude with a 90° phase difference give ______ polarization.", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "B" },
    { "chapter": 2, "id": "2-22", "q": "Two orthogonal field components with a 0° or integer-multiple-of-180° phase difference give ______ polarization.", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "A" },
    { "chapter": 2, "id": "2-23", "q": "Two orthogonal components of equal magnitude with a 45° phase difference give ______ polarization.", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "C" },
    { "chapter": 2, "id": "2-24", "q": "The factor that accounts for polarization mismatch between an incident wave and a receiving antenna is the:", "opts": ["(A) antenna efficiency", "(B) polarization loss factor", "(C) polarization ellipse"], "ans": "B" },
    { "chapter": 2, "id": "2-25", "q": "The maximum effective area of a small finite (triangular-current) dipole is typically ______ than the physical cross-sectional area.", "opts": ["(A) equal", "(B) greater", "(C) smaller"], "ans": "B" },
    { "chapter": 2, "id": "2-26", "q": "The maximum effective area of a λ/2 dipole (sinusoidal current) is typically ______ than its physical cross-sectional area.", "opts": ["(A) equal", "(B) greater", "(C) smaller"], "ans": "B" },
    { "chapter": 2, "id": "2-27", "q": "The real part of the input impedance of an antenna is the:", "opts": ["(A) radiation resistance", "(B) radiation reactance", "(C) reflection resistance"], "ans": "A" },
    { "chapter": 2, "id": "2-28", "q": "The ratio of radiation resistance to the sum of radiation and loss resistance is the:", "opts": ["(A) antenna efficiency", "(B) radiation efficiency", "(C) reflection efficiency"], "ans": "B" },
    { "chapter": 2, "id": "2-29", "q": "For a linear wire antenna, the maximum effective length is typically ______ than the physical length.", "opts": ["(A) greater", "(B) smaller", "(C) equal"], "ans": "B" },
    { "chapter": 2, "id": "2-30", "q": "For an aperture antenna, the maximum effective area is typically ______ than the physical area.", "opts": ["(A) greater", "(B) smaller", "(C) equal"], "ans": "B" },
    { "chapter": 2, "id": "2-31", "q": "The ratio of maximum effective area to physical area is the:", "opts": ["(A) antenna efficiency", "(B) reflection efficiency", "(C) aperture efficiency"], "ans": "C" },
    { "chapter": 2, "id": "2-32", "q": "The ratio of available power at a receiving antenna's terminals to the power density of the incident plane wave is the:", "opts": ["(A) effective length", "(B) effective area", "(C) directivity"], "ans": "B" },
    { "chapter": 2, "id": "2-33", "q": "The scattering characteristics of a radar target are usually represented by the:", "opts": ["(A) gain", "(B) directivity", "(C) radar cross section"], "ans": "C" },
    { "chapter": 2, "id": "2-34", "q": "The equation relating received to transmitted power for two antennas separated by a large distance R is the:", "opts": ["(A) radar range equation", "(B) Friis transmission equation", "(C) antenna temperature equation"], "ans": "B" },
    { "chapter": 2, "id": "2-35", "q": "The equation relating received to transmitted power after the signal is scattered by a radar target is the:", "opts": ["(A) radar range equation", "(B) Friis transmission equation", "(C) antenna temperature equation"], "ans": "A" },

    { "chapter": 4, "id": "4-1", "q": "The polarization of a linear dipole is:", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "A" },
    { "chapter": 4, "id": "4-2", "q": "Two collocated crossed dipoles (x and y), equal magnitude and same phase, observed perpendicular to their plane, are polarized:", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "A" },
    { "chapter": 4, "id": "4-3", "q": "The same crossed dipoles (equal magnitude, same phase), observed toward any angle, are polarized:", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "A" },
    { "chapter": 4, "id": "4-4", "q": "Two crossed dipoles (x and y), equal magnitude but a 90° phase difference, observed perpendicular to their plane, are polarized:", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "B" },
    { "chapter": 4, "id": "4-5", "q": "Two crossed dipoles, different magnitude and a 90° phase difference, observed toward a direction other than the perpendicular, are polarized:", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "C" },
    { "chapter": 4, "id": "4-6", "q": "Two crossed dipoles, different magnitude and 0° phase difference, observed perpendicular to their plane, are polarized:", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "A" },
    { "chapter": 4, "id": "4-7", "q": "Two crossed dipoles, equal magnitude and a 45° phase difference, observed perpendicular to their plane, are polarized:", "opts": ["(A) linear", "(B) circular", "(C) elliptical"], "ans": "C" },
    { "chapter": 4, "id": "4-8", "q": "PLF between two dipoles displaced along x in the same plane, one along z and one along x (far field), is ideally:", "opts": ["(A) 0 dB", "(B) -3 dB", "(C) -∞ dB"], "ans": "C" },
    { "chapter": 4, "id": "4-9", "q": "PLF between two dipoles displaced along x, one along z and one along y (far field), is ideally:", "opts": ["(A) 0 dB", "(B) -3 dB", "(C) -∞ dB"], "ans": "C" },
    { "chapter": 4, "id": "4-10", "q": "PLF between two dipoles displaced along x, one along x and one along y (far field), is ideally:", "opts": ["(A) 0 dB", "(B) -3 dB", "(C) -∞ dB"], "ans": "C" },
    { "chapter": 4, "id": "4-11", "q": "PLF between two dipoles displaced along x, both along z (far field), is ideally:", "opts": ["(A) 0 dB", "(B) -3 dB", "(C) -∞ dB"], "ans": "A" },
    { "chapter": 4, "id": "4-12", "q": "The minimum far-field distance for a maximum phase error of 22.5° (π/8) for an antenna of maximum dimension D is:", "opts": ["(A) D²/λ", "(B) 2D²/λ", "(C) 4D²/λ"], "ans": "B" },
    { "chapter": 4, "id": "4-13", "q": "The minimum far-field distance for a maximum phase error of 11.25° (π/16) for maximum dimension D is:", "opts": ["(A) D²/λ", "(B) 2D²/λ", "(C) 4D²/λ"], "ans": "C" },
    { "chapter": 4, "id": "4-14", "q": "Maximum directivity (dimensionless) of an infinitesimal dipole (uniform current) is:", "opts": ["(A) 1.5", "(B) 3", "(C) 1.65"], "ans": "A" },
    { "chapter": 4, "id": "4-15", "q": "Maximum directivity of a small finite-length dipole (triangular current) is:", "opts": ["(A) 1.5", "(B) 3", "(C) 1.65"], "ans": "A" },
    { "chapter": 4, "id": "4-16", "q": "Maximum directivity of a λ/2 dipole (sinusoidal current) is:", "opts": ["(A) 1.5", "(B) 3", "(C) 1.65"], "ans": "C" },
    { "chapter": 4, "id": "4-17", "q": "Radiation resistance of an infinitesimal dipole (uniform current) is:", "opts": ["(A) 20π²(L/λ)²", "(B) 40π²(L/λ)²", "(C) 80π²(L/λ)²"], "ans": "C" },
    { "chapter": 4, "id": "4-18", "q": "The radiated power of a small finite (triangular-current) dipole is ______ that of an infinitesimal (uniform-current) dipole.", "opts": ["(A) equal", "(B) twice", "(C) one fourth"], "ans": "C" },
    { "chapter": 4, "id": "4-19", "q": "The radiation resistance of a small finite (triangular-current) dipole is ______ that of an infinitesimal (uniform-current) dipole.", "opts": ["(A) equal", "(B) twice", "(C) one fourth"], "ans": "C" },
    { "chapter": 4, "id": "4-20", "q": "The directivity of a small finite (triangular-current) dipole is ______ that of an infinitesimal (uniform-current) dipole.", "opts": ["(A) equal", "(B) twice", "(C) half"], "ans": "A" },
    { "chapter": 4, "id": "4-21", "q": "The maximum effective area of a small finite (triangular-current) dipole is ______ that of an infinitesimal (uniform-current) dipole.", "opts": ["(A) equal", "(B) twice", "(C) half"], "ans": "A" },
    { "chapter": 4, "id": "4-22", "q": "The maximum effective length of an infinitesimal dipole (uniform current) is ______ its physical length.", "opts": ["(A) equal", "(B) greater", "(C) smaller"], "ans": "A" },
    { "chapter": 4, "id": "4-23", "q": "The maximum effective length of a small finite (triangular-current) dipole is ______ its physical length.", "opts": ["(A) equal", "(B) greater", "(C) smaller"], "ans": "C" },
    { "chapter": 4, "id": "4-24", "q": "The maximum effective length of a λ/2 dipole (sinusoidal current) is ______ its physical length.", "opts": ["(A) equal", "(B) greater", "(C) smaller"], "ans": "C" },
    { "chapter": 4, "id": "4-25", "q": "The maximum effective area of an infinitesimal dipole (uniform current) is typically ______ than its physical cross-sectional area.", "opts": ["(A) equal", "(B) greater", "(C) smaller"], "ans": "B" },
    { "chapter": 4, "id": "4-26", "q": "The maximum effective area of a small finite (triangular-current) dipole is typically ______ than its physical cross-sectional area.", "opts": ["(A) equal", "(B) greater", "(C) smaller"], "ans": "B" },
    { "chapter": 4, "id": "4-27", "q": "The maximum effective area of a λ/2 dipole (sinusoidal current) is typically ______ than its physical cross-sectional area.", "opts": ["(A) equal", "(B) greater", "(C) smaller"], "ans": "B" },
    { "chapter": 4, "id": "4-28", "q": "The input impedance of a λ/2 dipole (sinusoidal current) is approximately:", "opts": ["(A) 50 + j100 Ω", "(B) 73 + j42.5 Ω", "(C) 100 + j25 Ω"], "ans": "B" },
    { "chapter": 4, "id": "4-29", "q": "The input impedance of a λ/4 monopole is ______ that of its equivalent λ/2 dipole.", "opts": ["(A) equal", "(B) twice", "(C) half"], "ans": "C" },
    { "chapter": 4, "id": "4-30", "q": "The directivity of a λ/4 monopole is ______ that of its equivalent λ/2 dipole.", "opts": ["(A) equal", "(B) twice", "(C) half"], "ans": "B" },
    { "chapter": 4, "id": "4-31", "q": "The normalized amplitude pattern (shape) above ground of a λ/4 monopole is ______ that of its equivalent λ/2 dipole.", "opts": ["(A) same", "(B) different", "(C) twice"], "ans": "A" },
    { "chapter": 4, "id": "4-32", "q": "As the length of a linear dipole increases from very small up to one wavelength, the beamwidth:", "opts": ["(A) increases", "(B) decreases", "(C) stays the same"], "ans": "B" },
    { "chapter": 4, "id": "4-33", "q": "As the length of a linear dipole increases from very small up to one wavelength, the maximum directivity:", "opts": ["(A) increases", "(B) decreases", "(C) stays the same"], "ans": "A" },
    { "chapter": 4, "id": "4-34", "q": "The radiation resistance and the input resistance of a general dipole are, in general:", "opts": ["(A) the same", "(B) different", "(C) one is twice the other"], "ans": "B" },
    { "chapter": 4, "id": "4-35", "q": "The reflection coefficient for a vertical (perpendicular) dipole above a PEC is:", "opts": ["(A) +1", "(B) -1", "(C) (1+j1)/2"], "ans": "A" },
    { "chapter": 4, "id": "4-36", "q": "The reflection coefficient for a horizontal (parallel) dipole above a PEC is:", "opts": ["(A) +1", "(B) -1", "(C) (1+j1)/2"], "ans": "B" },
    { "chapter": 4, "id": "4-37", "q": "The reflection coefficient for a vertical dipole above a PMC is:", "opts": ["(A) +1", "(B) -1", "(C) (1+j1)/2"], "ans": "B" },
    { "chapter": 4, "id": "4-38", "q": "The reflection coefficient for a horizontal dipole above a PMC is:", "opts": ["(A) +1", "(B) -1", "(C) (1+j1)/2"], "ans": "A" },
    { "chapter": 4, "id": "4-39", "q": "The reflection coefficient of a vertical dipole above a flat lossy surface, near the horizon (grazing, < ~3°), is approximately:", "opts": ["(A) +1", "(B) -1", "(C) (1+j1)"], "ans": "B" },
    { "chapter": 4, "id": "4-40", "q": "The reflection coefficient of a vertical dipole above a flat lossy surface, for all angles other than grazing, is approximately:", "opts": ["(A) +1", "(B) -1", "(C) (1+j1)"], "ans": "A" },
    { "chapter": 4, "id": "4-41", "q": "The reflection coefficient of a horizontal dipole above a flat lossy surface, for almost all angles, is approximately:", "opts": ["(A) +1", "(B) -1", "(C) (1+j1)"], "ans": "B" },
    { "chapter": 4, "id": "4-42", "q": "The number of lobes of a vertical dipole above a PEC, for large heights, is approximately:", "opts": ["(A) h/λ", "(B) 2h/λ", "(C) 2h/λ + 1"], "ans": "B" },
    { "chapter": 4, "id": "4-43", "q": "The number of lobes of a horizontal dipole above a PEC, for large heights, is approximately:", "opts": ["(A) h/λ", "(B) 2h/λ", "(C) 2h/λ + 1"], "ans": "C" },
    { "chapter": 4, "id": "4-44", "q": "The reactance of a very small dipole made of very thin wire is primarily:", "opts": ["(A) inductive", "(B) capacitive", "(C) resistive"], "ans": "B" },
    { "chapter": 4, "id": "4-45", "q": "The divergence factor accounts for the ______ of the reflecting surface.", "opts": ["(A) losses", "(B) curvature", "(C) roughness"], "ans": "B" },
    { "chapter": 4, "id": "4-46", "q": "For earth applications the divergence factor is usually less than unity for observation angles:", "opts": ["(A) within ~3° of the horizon (grazing)", "(B) near zenith (perpendicular)", "(C) between ~3° from horizon and zenith"], "ans": "A" },

    { "chapter": 14, "id": "14-1", "q": "The most popular microstrip patch shapes are:", "opts": ["(A) rectangular and circular", "(B) triangular and elliptical", "(C) circular ring and ring sector"], "ans": "A" },
    { "chapter": 14, "id": "14-2", "q": "A microstrip antenna is usually classified as:", "opts": ["(A) narrowband", "(B) medium band", "(C) broadband"], "ans": "A" },
    { "chapter": 14, "id": "14-3", "q": "The typical bandwidth of a microstrip antenna is usually:", "opts": ["(A) less than 15%", "(B) around 30%", "(C) greater than 40%"], "ans": "A" },
    { "chapter": 14, "id": "14-4", "q": "The feeding mechanism with the largest bandwidth is the:", "opts": ["(A) microstrip line", "(B) probe", "(C) proximity-coupling"], "ans": "C" },
    { "chapter": 14, "id": "14-5", "q": "For a typical microstrip antenna, the substrate height is usually:", "opts": ["(A) much smaller than the patch width", "(B) about the same as the patch width", "(C) greater than the patch width"], "ans": "A" },
    { "chapter": 14, "id": "14-6", "q": "The simplest analysis model is the:", "opts": ["(A) transmission-line", "(B) cavity", "(C) integral equation/method of moments"], "ans": "A" },
    { "chapter": 14, "id": "14-7", "q": "The model that is simplest and gives physical insight is the:", "opts": ["(A) transmission-line", "(B) cavity", "(C) integral equation/method of moments"], "ans": "A" },
    { "chapter": 14, "id": "14-8", "q": "The most accurate model is the:", "opts": ["(A) transmission-line", "(B) cavity", "(C) integral equation/method of moments"], "ans": "C" },
    { "chapter": 14, "id": "14-9", "q": "The model that is simple, gives physical insight, AND is relatively accurate is the:", "opts": ["(A) transmission-line", "(B) cavity", "(C) integral equation/method of moments"], "ans": "B" },
    { "chapter": 14, "id": "14-10", "q": "A rectangular microstrip antenna has how many radiating slots?", "opts": ["(A) two", "(B) three", "(C) four"], "ans": "A" },
    { "chapter": 14, "id": "14-11", "q": "In the transmission-line model, the number of NON-radiating slots is:", "opts": ["(A) two", "(B) three", "(C) four"], "ans": "A" },
    { "chapter": 14, "id": "14-12", "q": "In the transmission-line model, the radiating slots are represented by an:", "opts": ["(A) equivalent circuit", "(B) electric and magnetic fields", "(C) open circuit"], "ans": "A" },
    { "chapter": 14, "id": "14-13", "q": "In the cavity model, the radiating slots are represented by:", "opts": ["(A) equivalent circuit", "(B) electric and magnetic fields", "(C) open circuit"], "ans": "B" },
    { "chapter": 14, "id": "14-14", "q": "For a typical microstrip line with air above the conductor, the effective dielectric constant is:", "opts": ["(A) less than unity", "(B) between unity and the substrate's dielectric constant", "(C) greater than the substrate's dielectric constant"], "ans": "B" },
    { "chapter": 14, "id": "14-15", "q": "In a microstrip line/antenna, the effective dielectric constant accounts for the:", "opts": ["(A) impedance of the radiating slots", "(B) fringing of the fields", "(C) geometry of the patch/conductor"], "ans": "B" },
    { "chapter": 14, "id": "14-16", "q": "Field fringing in a microstrip is also accounted for by:", "opts": ["(A) assigning an impedance for the aperture", "(B) defining an effective length", "(C) including an effective height"], "ans": "B" },
    { "chapter": 14, "id": "14-17", "q": "The width of a rectangular microstrip patch is chosen to:", "opts": ["(A) control the bandwidth", "(B) give good radiation efficiency", "(C) reduce the fringing"], "ans": "B" },
    { "chapter": 14, "id": "14-18", "q": "The characteristic impedance of a microstrip line (all else fixed) is increased by:", "opts": ["(A) increasing the conductor width", "(B) decreasing the conductor width", "(C) clipping the conductor"], "ans": "B" },
    { "chapter": 14, "id": "14-19", "q": "For a resonant rectangular microstrip antenna, the input impedance is:", "opts": ["(A) proportional to the aperture conductance", "(B) inversely proportional to the aperture conductance", "(C) inversely proportional to twice the aperture conductance"], "ans": "C" },
    { "chapter": 14, "id": "14-20", "q": "For a rectangular microstrip fed by a transmission line, the input impedance is controlled by:", "opts": ["(A) using a recessed (inset) microstrip-line feed", "(B) placing a lumped element at the aperture", "(C) short-circuiting the second aperture"], "ans": "A" },
    { "chapter": 14, "id": "14-21", "q": "The input impedance of a rectangular microstrip fed at the center of its length is ideally:", "opts": ["(A) open circuit", "(B) short circuit", "(C) an impedance of finite value"], "ans": "B" },
    { "chapter": 14, "id": "14-22", "q": "From the radiating edge toward the center, the input impedance of a rectangular microstrip varies as:", "opts": ["(A) sine squared", "(B) cosine squared", "(C) cosine"], "ans": "B" },
    { "chapter": 14, "id": "14-23", "q": "In the cavity model the microstrip is modeled as a:", "opts": ["(A) lossless transmission line", "(B) cavity", "(C) leaky transmission line"], "ans": "B" },
    { "chapter": 14, "id": "14-24", "q": "In the cavity model, the upper and lower walls of the rectangular cavity are modeled as:", "opts": ["(A) PEC", "(B) PMC", "(C) open circuit"], "ans": "A" },
    { "chapter": 14, "id": "14-25", "q": "In the cavity model, the four side walls of the cavity are modeled as:", "opts": ["(A) PEC", "(B) PMC", "(C) open circuit"], "ans": "B" },
    { "chapter": 14, "id": "14-26", "q": "For thin substrates, the modes supported by a rectangular microstrip are:", "opts": ["(A) TE", "(B) TM", "(C) TEM"], "ans": "B" },
    { "chapter": 14, "id": "14-27", "q": "Using the equivalence principle, the side walls of a rectangular microstrip in free space (no ground plane) are represented ultimately by:", "opts": ["(A) electric current densities", "(B) magnetic current densities", "(C) electric and magnetic current densities"], "ans": "B" },
    { "chapter": 14, "id": "14-28", "q": "A rectangular microstrip is modeled, via its two radiating slots, as a:", "opts": ["(A) two-element array", "(B) four-element array", "(C) six-element array"], "ans": "A" },
    { "chapter": 14, "id": "14-29", "q": "The far-zone E-plane pattern of a rectangular microstrip (cavity model) is, about the perpendicular to the patch:", "opts": ["(A) symmetrical", "(B) asymmetrical", "(C) neither"], "ans": "A" },
    { "chapter": 14, "id": "14-30", "q": "The far-zone E-plane pattern (integral-equation model or measurement with the probe feed) is, about the perpendicular:", "opts": ["(A) symmetrical", "(B) asymmetrical", "(C) neither"], "ans": "B" },
    { "chapter": 14, "id": "14-31", "q": "The far-zone H-plane pattern of a rectangular microstrip (cavity model) is, about the perpendicular:", "opts": ["(A) symmetrical", "(B) asymmetrical", "(C) neither"], "ans": "A" },
    { "chapter": 14, "id": "14-32", "q": "The far-zone H-plane pattern (integral-equation model or measurement with probe feed) is, about the perpendicular:", "opts": ["(A) symmetrical", "(B) asymmetrical", "(C) neither"], "ans": "A" },
    { "chapter": 14, "id": "14-33", "q": "The cavity-model E-plane pattern does NOT vanish toward grazing because, beyond the patch edges, the microstrip is modeled as:", "opts": ["(A) PEC", "(B) impedance surface", "(C) admittance surface"], "ans": "A" },
    { "chapter": 14, "id": "14-34", "q": "The integral-equation E-plane pattern DOES vanish toward grazing because, beyond the patch edges, the microstrip is modeled as:", "opts": ["(A) PEC", "(B) impedance surface", "(C) admittance surface"], "ans": "B" },
    { "chapter": 14, "id": "14-35", "q": "The H-plane patterns are nearly the same for the cavity and integral-equation models because, beyond the edges, the microstrip basically acts as:", "opts": ["(A) PEC", "(B) PMC", "(C) open circuit"], "ans": "A" },
    { "chapter": 14, "id": "14-36", "q": "In the cavity model the circular microstrip is modeled as a:", "opts": ["(A) lossless transmission line", "(B) cavity", "(C) leaky transmission line"], "ans": "B" },
    { "chapter": 14, "id": "14-37", "q": "In the cavity model, the upper and lower walls of the circular cavity are modeled as:", "opts": ["(A) PEC", "(B) PMC", "(C) open circuit"], "ans": "A" },
    { "chapter": 14, "id": "14-38", "q": "In the cavity model, the peripheral (side) wall of the circular cavity is modeled as:", "opts": ["(A) PEC", "(B) PMC", "(C) open circuit"], "ans": "B" },
    { "chapter": 14, "id": "14-39", "q": "Using the equivalence principle, the peripheral side of a circular microstrip in free space is represented ultimately by:", "opts": ["(A) electric current densities", "(B) magnetic current densities", "(C) electric and magnetic current densities"], "ans": "B" },
    { "chapter": 14, "id": "14-40", "q": "The circular-microstrip E-plane pattern (cavity model) is, about the perpendicular to the patch:", "opts": ["(A) symmetrical", "(B) asymmetrical", "(C) neither"], "ans": "A" },
    { "chapter": 14, "id": "14-41", "q": "The circular-microstrip E-plane pattern (cavity model) is, relative to the ground plane:", "opts": ["(A) symmetrical", "(B) asymmetrical", "(C) neither"], "ans": "A" },
    { "chapter": 14, "id": "14-42", "q": "The circular-microstrip E-plane pattern (integral-equation/measurement with probe feed) is, about the perpendicular:", "opts": ["(A) symmetrical", "(B) asymmetrical", "(C) neither"], "ans": "B" },
    { "chapter": 14, "id": "14-43", "q": "The circular-microstrip H-plane pattern (integral-equation/measurement with probe feed) is, about the perpendicular:", "opts": ["(A) symmetrical", "(B) asymmetrical", "(C) neither"], "ans": "A" },
    { "chapter": 14, "id": "14-44", "q": "The cavity-model circular E-plane pattern does NOT vanish at grazing because, beyond the edges, the microstrip is modeled as:", "opts": ["(A) PEC", "(B) impedance surface", "(C) admittance surface"], "ans": "A" },
    { "chapter": 14, "id": "14-45", "q": "The integral-equation circular E-plane pattern DOES vanish at grazing because, beyond the edges, the microstrip is modeled as:", "opts": ["(A) PEC", "(B) impedance surface", "(C) admittance surface"], "ans": "B" },
    { "chapter": 14, "id": "14-46", "q": "The H-plane patterns of a circular microstrip are nearly the same for both models because, beyond the edges, it basically acts as:", "opts": ["(A) PEC", "(B) PMC", "(C) open circuit"], "ans": "A" },
    { "chapter": 14, "id": "14-47", "q": "The E-plane patterns of a rectangular and a circular microstrip of similar dimensions are basically:", "opts": ["(A) identical", "(B) similar", "(C) quite different"], "ans": "B" },
    { "chapter": 14, "id": "14-48", "q": "The H-plane patterns of a rectangular and a circular microstrip of similar dimensions are basically:", "opts": ["(A) identical", "(B) similar", "(C) quite different"], "ans": "B" },
    { "chapter": 14, "id": "14-49", "q": "Using the cavity model, the modes of a circular microstrip with a thin substrate are basically:", "opts": ["(A) TE", "(B) TM", "(C) TEM"], "ans": "B" },
    { "chapter": 14, "id": "14-50", "q": "For a circular microstrip, fringing is accounted for using an:", "opts": ["(A) effective height", "(B) effective radius", "(C) effective thickness of the patch"], "ans": "B" },
    { "chapter": 14, "id": "14-51", "q": "The bandwidth of a microstrip antenna is:", "opts": ["(A) proportional to the dielectric constant", "(B) inversely proportional to the dielectric constant", "(C) inversely proportional to the square root of the dielectric constant"], "ans": "B" },
    { "chapter": 14, "id": "14-52", "q": "Microstrip antennas:", "opts": ["(A) are always linearly polarized", "(B) are always circularly polarized", "(C) can be designed for basically linear or circular polarization"], "ans": "C" },
    { "chapter": 14, "id": "14-53", "q": "To achieve circular polarization with a microstrip antenna (besides the feeding technique) one must introduce a:", "opts": ["(A) 90° time-phase difference", "(B) effective dielectric constant", "(C) effective length and/or radius"], "ans": "A" },
    { "chapter": 14, "id": "14-54", "q": "Microstrip antennas can be used:", "opts": ["(A) only as single elements", "(B) only in arrays", "(C) both as single elements and/or in arrays"], "ans": "C" },
    { "chapter": 14, "id": "14-55", "q": "In microstrip arrays, scan blindness is primarily caused by:", "opts": ["(A) space waves", "(B) surface waves", "(C) radiating waves"], "ans": "B" },
    { "chapter": 14, "id": "14-56", "q": "Surface waves in a traditional microstrip array can be eliminated by using:", "opts": ["(A) cavities", "(B) impedance loads", "(C) admittance loads"], "ans": "A" },
    { "chapter": 14, "id": "14-57", "q": "The pattern usually most affected by scan blindness in a microstrip array is the:", "opts": ["(A) E-plane", "(B) H-plane", "(C) D-plane (between E and H)"], "ans": "A" },
    { "chapter": 14, "id": "14-58", "q": "The pattern most affected by the presence of cavities in a microstrip array is the:", "opts": ["(A) E-plane", "(B) H-plane", "(C) D-plane (between E and H)"], "ans": "B" },
    { "chapter": 14, "id": "14-59", "q": "The shape of the cavity (square vs circular) in a microstrip array ______ the input reflection coefficient in the E-plane versus scan angle.", "opts": ["(A) does make a slight difference in", "(B) does not make any difference in", "(C) does make a big difference in"], "ans": "B" },
    { "chapter": 14, "id": "14-60", "q": "The shape of the cavity (square vs circular) in a microstrip array ______ the input reflection coefficient in the H-plane versus scan angle.", "opts": ["(A) does make a slight difference in", "(B) does not make any difference in", "(C) does make a big difference in"], "ans": "A" },

    { "chapter": 6, "id": "6-1", "q": "Neglecting coupling, the total field of an array of identical elements is obtained by:", "opts": ["(A) the array factor alone", "(B) pattern multiplication", "(C) the element pattern alone"], "ans": "B" },
    { "chapter": 6, "id": "6-2", "q": "For two in-phase, equal-amplitude isotropic sources, the minimum spacing to form at least one null in the array factor is:", "opts": ["(A) λ/4", "(B) λ/2", "(C) λ"], "ans": "B" },
    { "chapter": 6, "id": "6-3", "q": "For two equal-amplitude isotropic sources with a 90° phase difference, the minimum spacing for at least one null is:", "opts": ["(A) λ/4", "(B) λ/2", "(C) λ"], "ans": "A" },
    { "chapter": 6, "id": "6-4", "q": "Maximum spacing of two isotropic sources for ordinary end-fire in one direction only:", "opts": ["(A) d < λ/2", "(B) d = λ/2", "(C) d > λ/2"], "ans": "A" },
    { "chapter": 6, "id": "6-5", "q": "Maximum spacing for ordinary end-fire in both directions only:", "opts": ["(A) d < λ/2", "(B) d = λ/2", "(C) d > λ/2"], "ans": "B" },
    { "chapter": 6, "id": "6-6", "q": "Maximum spacing for end-fire in both directions AND broadside simultaneously:", "opts": ["(A) d < λ/2", "(B) d = λ", "(C) d > λ"], "ans": "B" },
    { "chapter": 6, "id": "6-7", "q": "Maximum spacing for end-fire in one direction plus one other direction (not broadside):", "opts": ["(A) d < λ/2", "(B) d between λ/2 and λ", "(C) d > λ"], "ans": "B" },
    { "chapter": 6, "id": "6-8", "q": "The sidelobe level of a uniform array is approximately:", "opts": ["(A) -26 dB", "(B) -13.5 dB", "(C) -30 dB"], "ans": "B" },
    { "chapter": 6, "id": "6-9", "q": "Scanning of the array pattern is accomplished primarily by controlling the:", "opts": ["(A) amplitude distribution", "(B) phase distribution", "(C) element spacing"], "ans": "B" },
