    { "chapter": 6, "id": "6-11", "q": "For ordinary end-fire toward θ = 0° from a uniform linear array, the phasing must be:", "opts": ["(A) β = +kd", "(B) β = -kd", "(C) β = 0"], "ans": "B" },
    { "chapter": 6, "id": "6-12", "q": "For ordinary end-fire toward θ = 180° from a uniform linear array, the phasing must be:", "opts": ["(A) β = +kd", "(B) β = -kd", "(C) β = 0"], "ans": "A" },
    { "chapter": 6, "id": "6-13", "q": "For Hansen–Woodyard end-fire toward θ = 0° (N elements), the phasing must be:", "opts": ["(A) β ~ +(kd + π/N)", "(B) β ~ -(kd + π/N)", "(C) β ~ +/- kd"], "ans": "B" },
    { "chapter": 6, "id": "6-14", "q": "For Hansen–Woodyard end-fire toward θ = 180° (N elements), the phasing must be:", "opts": ["(A) β ~ +(kd + π/N)", "(B) β ~ -(kd + π/N)", "(C) β ~ +/- kd"], "ans": "A" },
    { "chapter": 6, "id": "6-15", "q": "A Hansen–Woodyard end-fire uniform array gives a greater:", "opts": ["(A) half-power beamwidth", "(B) directivity", "(C) scanning angle"], "ans": "B" },
    { "chapter": 6, "id": "6-16", "q": "A Hansen–Woodyard end-fire uniform array gives a smaller:", "opts": ["(A) half-power beamwidth", "(B) directivity", "(C) scanning angle"], "ans": "A" },
    { "chapter": 6, "id": "6-17", "q": "For a large-N Hansen–Woodyard array, the approximate element spacing should be:", "opts": ["(A) λ", "(B) λ/2", "(C) λ/4"], "ans": "C" },
    { "chapter": 6, "id": "6-18", "q": "For a large-N Hansen–Woodyard array, the approximate increase in directivity (over ordinary end-fire) is about:", "opts": ["(A) 13.5 dB", "(B) 2.5 dB", "(C) 0 dB"], "ans": "B" },
    { "chapter": 6, "id": "6-19", "q": "For a large-N Hansen–Woodyard array, the approximate sidelobe level is:", "opts": ["(A) -13.5 dB", "(B) -26 dB", "(C) -9 dB"], "ans": "C" },
    { "chapter": 6, "id": "6-20", "q": "The directivity of an ordinary end-fire linear array (large N, single maximum), compared with a broadside array of the same N, is:", "opts": ["(A) larger", "(B) same", "(C) smaller"], "ans": "A" },
