    { "chapter": 6, "id": "6-27", "q": "With spacing d ≤ λ/2, the amplitude taper giving the lowest sidelobe level is:", "opts": ["(A) uniform", "(B) binomial", "(C) Dolph–Tschebyscheff"], "ans": "B" },
