    { "chapter": 6, "id": "6-29", "q": "A binomial non-uniform array with equal phases and spacing d = λ gives a:", "opts": ["(A) broadside array", "(B) end-fire array (one direction)", "(C) end-fire array (both directions)", "(D) both broadside and end-fire (both directions)"], "ans": "D" },
    { "chapter": 6, "id": "6-30", "q": "A binomial array with many elements is usually impractical because of the:", "opts": ["(A) large half-power beamwidth", "(B) low sidelobe level", "(C) large amplitude taper between center and edge elements"], "ans": "C" },
    { "chapter": 6, "id": "6-31", "q": "Binomial excitation amplitude coefficients can be obtained using:", "opts": ["(A) a Taylor series expansion", "(B) a binomial series expansion", "(C) Pascal's triangle", "(D) both the binomial series and Pascal's triangle"], "ans": "D" },
