    { "chapter": 6, "id": "6-44", "q": "For a Dolph–Tschebyscheff design of any sidelobe level, the amplitude taper from center to edge is, in general:", "opts": ["(A) monotonically decreasing", "(B) monotonically increasing", "(C) decreasing then increasing"], "ans": "C" },
    { "chapter": 6, "id": "6-45", "q": "A superdirective array has a directivity usually greater than that of a ______ array with the same number of elements and spacing.", "opts": ["(A) uniform", "(B) binomial", "(C) Dolph–Tschebyscheff"], "ans": "A" },
