def clear_layout(layout):
    if layout is not None:
        while layout.count():
            item = layout.takeAt(0)
            widget = item.widget()
            if widget is not None:
                widget.deleteLater()
            else:
                clear_layout(item.layout())

class AntennaQuizApp(QMainWindow):
    def __init__(self):
        super().__init__()
        self.lang = 'GR'
        self.strings = UI_STRINGS[self.lang]
        
        self.setWindowTitle(self.strings['title'])
        self.setMinimumSize(700, 800)
        
        self.selected_mode = None
        self.questions = []
        self.current = 0
        self.answers = {}
        self.show_wrong = False
        
        self.setStyleSheet("""
            QMainWindow {
                background-color: #F0F2F5;
                font-family: 'Segoe UI', Arial, sans-serif;
            }
            QLabel {
                font-family: 'Segoe UI', Arial, sans-serif;
            }
            QPushButton {
                font-family: 'Segoe UI', Arial, sans-serif;
            }
        """)

        self.central_widget = QWidget()
        self.setCentralWidget(self.central_widget)
        self.main_layout = QVBoxLayout(self.central_widget)
        self.main_layout.setContentsMargins(0, 0, 0, 0)
        
        # Header for language toggle
        self.top_bar_layout = QHBoxLayout()
        self.top_bar_layout.setContentsMargins(20, 15, 20, 0)
        self.lang_btn = QPushButton("🌐 ΕΛ / EN")
        self.lang_btn.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        self.lang_btn.setFixedSize(100, 35)
        self.lang_btn.setStyleSheet("""
            QPushButton {
                background-color: #FFFFFF; border: 1px solid #D0D0D0; border-radius: 17px; 
                font-weight: bold; color: #333333;
            }
            QPushButton:hover { background-color: #EAEAEA; }
        """)
        self.lang_btn.clicked.connect(self.toggle_language)
        self.top_bar_layout.addStretch()
        self.top_bar_layout.addWidget(self.lang_btn)
        self.main_layout.addLayout(self.top_bar_layout)
        
        self.stacked_widget = QStackedWidget()
        self.main_layout.addWidget(self.stacked_widget)
        
        # Setup screens
        self.menu_widget = QWidget()
        self.quiz_widget = QWidget()
        self.results_widget = QWidget()
        
        self.setup_menu_screen()
        self.setup_quiz_screen()
        self.setup_results_screen()
        
        self.stacked_widget.addWidget(self.menu_widget)
        self.stacked_widget.addWidget(self.quiz_widget)
        self.stacked_widget.addWidget(self.results_widget)

    def toggle_language(self):
        self.lang = 'EN' if self.lang == 'GR' else 'GR'
        self.strings = UI_STRINGS[self.lang]
        self.setWindowTitle(self.strings['title'])
        self.update_menu_texts()
        
        # If mid-quiz, update the active quiz strings without changing the question pool yet
        if self.stacked_widget.currentWidget() == self.quiz_widget:
            self.render_quiz_screen()
        elif self.stacked_widget.currentWidget() == self.results_widget:
            self.render_results_screen()

    def build_questions(self, mode, chapter_filter=0):
        pool = ALL_QUESTIONS_GR if self.lang == 'GR' else ALL_QUESTIONS_EN
        if chapter_filter == 0:
            filtered_pool = pool[:]
        else:
            filtered_pool = [q for q in pool if q["chapter"] == chapter_filter]

        if mode == 1:
            return filtered_pool
        if mode == 2:
            shuffled = filtered_pool[:]
            random.shuffle(shuffled)
            return shuffled
        if mode == 3:
            if chapter_filter == 0:
                by_chapter = {}
                for q in filtered_pool:
                    ch = q["chapter"]
                    if ch not in by_chapter:
                        by_chapter[ch] = []
                    by_chapter[ch].append(q)
                pool_out = []
                for qs in by_chapter.values():
                    random.shuffle(qs)
                    pool_out.extend(qs)
                random.shuffle(pool_out)
                return pool_out[:50]
            else:
                shuffled = filtered_pool[:]
                random.shuffle(shuffled)
                return shuffled[:50]

